import React, { useState, useEffect } from 'react';
import './styles.css';

export default function SecureScore({ tenantId, tenantName }) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    const fetchScore = async () => {
      setLoading(true);
      setError('');
      try {
        const response = await fetch(
          `https://nordcomply-api.dshvan5.workers.dev/api/secure-score?tenantId=${tenantId}`
        );
        const result = await response.json();

        if (result.error) {
          setError(typeof result.error === 'string' ? result.error : JSON.stringify(result.error));
        } else {
          setData(result);
        }
      } catch (err) {
        setError(`Error: ${err.message}`);
      }
      setLoading(false);
    };

    fetchScore();
  }, [tenantId]);

  return (
    <div className="secure-score">
      <div>
        <h2>Secure Score - {tenantName}</h2>
        <p className="score-subtitle">Microsoft 365 and Identity security posture</p>
      </div>

      {loading && <p className="score-loading">Indlæser...</p>}
      {error && <div className="score-error">{error}</div>}

      {data && !loading && (
        <div className="score-container">
          {data.m365 && (
            <div className="score-card">
              <h3>Microsoft 365 Secure Score</h3>
              <div className="score-display">
                <div className="score-number">{data.m365.currentScore}</div>
                <div className="score-max">/ {data.m365.maxScore}</div>
              </div>
              <div className="progress-bar">
                <div
                  className="progress-fill"
                  style={{
                    width: `${(data.m365.currentScore / data.m365.maxScore) * 100}%`,
                  }}
                />
              </div>
              <p className="percentage">
                {((data.m365.currentScore / data.m365.maxScore) * 100).toFixed(1)}%
              </p>
            </div>
          )}

          {data.identity && (
            <div className="score-card">
              <h3>Identity Secure Score</h3>
              <div className="score-display">
                <div className="score-number">{data.identity.currentScore}</div>
                <div className="score-max">/ {data.identity.maxScore}</div>
              </div>
              <div className="progress-bar">
                <div
                  className="progress-fill"
                  style={{
                    width: `${(data.identity.currentScore / data.identity.maxScore) * 100}%`,
                  }}
                />
              </div>
              <p className="percentage">
                {((data.identity.currentScore / data.identity.maxScore) * 100).toFixed(1)}%
              </p>
            </div>
          )}

          {!data.m365 && !data.identity && (
            <div className="score-error">Ingen Secure Score data tilgængelig</div>
          )}
        </div>
      )}
    </div>
  );
}
